            if (fileName().endsWith("ts"))
                shell(`pnpm attest precache ${precachePath}`);
            // otherwise, just use npm to run the CLI command from build output
            else
                shell(`npm exec -c "attest precache ${precachePath}"`);
        });
    }
    return teardown;
};
